//! Target-agnostic monotonic clock for the corridor tick math.
//!
//! The broker converts elapsed time since construction into corridor ticks (`current_tick`) and
//! paces producers to green-window tick boundaries (`wait_for_tick`). On native this is wall-clock
//! `std::time::Instant`. On `wasm32-unknown-unknown` there is NO wall clock (`Instant::now()` panics
//! "time not implemented") and NO threads, so this module provides a **logical monotonic clock**: a
//! strictly-increasing tick counter advanced on each read. That keeps the corridor's admission /
//! back-pressure semantics (in-flight accounting, green-window tiling, peak tracking) fully live in
//! a single-threaded wasm host — the HOST paces which frames are fed and how often (the documented
//! "the scheduler stays host-side; the lib processes whatever window it is handed" contract), so the
//! corridor governs cadence/stability without needing to block on a wall clock it does not have.
//!
//! This is the sovereign fix for antiqueue on wasm (rather than gating the corridor out): the
//! corridor is part of the perception hot path and must run on the edge.

use std::time::Duration;

/// A monotonic clock the broker reads to compute corridor ticks. One per broker.
pub struct MonoClock {
    #[cfg(not(target_arch = "wasm32"))]
    t0: std::time::Instant,
    /// Logical tick counter for the wasm path (no wall clock). Each `current_tick` read returns the
    /// next strictly-greater value, so producers tile into successive green windows deterministically.
    #[cfg(target_arch = "wasm32")]
    logical: std::sync::atomic::AtomicU64,
}

impl MonoClock {
    /// Start the clock at "now".
    pub fn start() -> Self {
        #[cfg(not(target_arch = "wasm32"))]
        {
            MonoClock { t0: std::time::Instant::now() }
        }
        #[cfg(target_arch = "wasm32")]
        {
            MonoClock { logical: std::sync::atomic::AtomicU64::new(0) }
        }
    }

    /// Current corridor tick = elapsed-since-start / `tick_width`, floor-divided.
    ///
    /// Native: wall-clock elapsed. Wasm: a logical counter that advances by one each read (the host
    /// drives one read per fed frame), so corridor admission proceeds monotonically without a clock.
    #[inline]
    pub fn current_tick(&self, tick_width: Duration) -> u32 {
        #[cfg(not(target_arch = "wasm32"))]
        {
            let now_ns = self.t0.elapsed().as_nanos();
            let tick_ns = tick_width.as_nanos().max(1);
            (now_ns / tick_ns) as u32
        }
        #[cfg(target_arch = "wasm32")]
        {
            let _ = tick_width; // logical ticks are clock-free; width is implicit (one tick per read)
            use std::sync::atomic::Ordering;
            self.logical.fetch_add(1, Ordering::Relaxed) as u32
        }
    }

    /// Block until `target_tick` arrives on this clock.
    ///
    /// Native: sleep + spin to the wall-clock deadline. Wasm: a no-op — there is no blocking clock and
    /// no threads, and the host owns pacing (it decides when to feed the next frame). The corridor's
    /// rate limit is still expressed through `current_tick` advancing and the in-flight accounting.
    #[inline]
    pub fn wait_for_tick(&self, target_tick: u32, tick_width: Duration) {
        #[cfg(not(target_arch = "wasm32"))]
        {
            let deadline = self.t0 + tick_width * target_tick;
            let now = std::time::Instant::now();
            if now >= deadline {
                return;
            }
            let remaining = deadline - now;
            // Sub-200µs: spin (sleep floor on macOS is ~50µs). Otherwise sleep, then spin the residue.
            if remaining > Duration::from_micros(200) {
                std::thread::sleep(remaining - Duration::from_micros(100));
            }
            while std::time::Instant::now() < deadline {
                std::hint::spin_loop();
            }
        }
        #[cfg(target_arch = "wasm32")]
        {
            let _ = (target_tick, tick_width); // host-paced; no clock/thread to wait on
        }
    }
}
